import { generateText, tool } from 'ai';
import { z } from 'zod';

const approveStep = tool({
  description: 'Request human approval for critical steps',
  parameters: z.object({
    step: z.string().describe('Workflow step needing approval'),
    details: z.string(),
  }),
  execute: async ({ step, details }) => {
    // Store for human approval endpoint
    await kv.set(`approval:${step}`, { details, status: 'pending' });
    return { approved: false, message: 'Awaiting human approval' };
  },
});

export async function executeWorkflow(userId: string, task: string) {
  const { text, toolResults } = await generateText({
    model: 'openai/gpt-4o',
    prompt: `Execute workflow: ${task}`,
    tools: { approveStep },
    maxTokens: 2000,
  });
  return { result: text, tools: toolResults };
}

import { streamText } from 'ai';
import { createStreamableValue } from 'ai/rsc';

export default async function WorkflowStream({ task }: { task: string }) {
  const stream = await streamText({
    model: 'openai/gpt-4o',
    prompt: `Process workflow task: ${task}`,
  });

  const result = createStreamableValue('');
  (async () => {
    for await (const delta of stream.textStream) {
      result.update(delta);
    }
    result.done();
  })();

  return (
    <div>
      <p>Workflow Status: {result.value}</p>
      <ApprovalModal task={task} />
    </div>
  );
}

import { tool } from 'ai';
import { z } from 'zod';

const idempotentApiCall = tool({
  description: 'Make idempotent external API call',
  parameters: z.object({
    endpoint: z.string(),
    payload: z.record(z.unknown()),
    idempotencyKey: z.string(),
  }),
  execute: async ({ endpoint, payload, idempotencyKey }) => {
    const cacheKey = `api:${idempotencyKey}`;
    const cached = await kv.get(cacheKey);
    if (cached) return cached;

    const response = await fetch(endpoint, {
      method: 'POST',
      headers: { 'Idempotency-Key': idempotencyKey },
      body: JSON.stringify(payload),
    });

    const result = await response.json();
    await kv.set(cacheKey, result, { ex: 3600 });
    return result;
  },
});

import { actionClient } from './actions';
import { executeWorkflow } from './agent';

export const approveWorkflow = actionClient
  .schema(z.object({
    stepId: z.string(),
    approved: z.boolean(),
    userId: z.string(),
  }))
  .action(async ({ stepId, approved, userId }) => {
    if (!approved) {
      await rollbackWorkflow(stepId);
      return { status: 'rejected', message: 'Workflow rolled back' };
    }

    await kv.set(`approval:${stepId}`, { status: 'approved' });
    const workflowState = await getWorkflowState(stepId);
    const result = await executeWorkflow(userId, workflowState.nextTask);

    return { status: 'approved', result };
  });

