import { createVex } from '@vex_dev/sdk';
import { generateText } from 'ai';

const vex = createVex({
  projectId: process.env.VEX_PROJECT_ID!,
  apiKey: process.env.VEX_API_KEY!,
});

export async function verifiedGenerateText(params: any) {
  // Define verification spec for workflow actions
  const spec = {
    name: 'workflow-action',
    assertions: [
      { type: 'action_correctness', threshold: 0.95 },
      { type: 'permission_check', roles: ['workflow:execute'] },
    ],
    rollback: true,
  };

  const result = await generateText(params);

  // Verify tool calls and structured output
  const verified = await vex.verify({
    input: params.prompt,
    output: result.text,
    tools: result.toolResults,
    spec,
  });

  if (!verified.valid) {
    await vex.rollback({ traceId: verified.traceId });
    throw new Error(`Verification failed: ${verified.errors}`);
  }

  return result;
}

import { createVex } from '@vex_dev/sdk';
import { streamText } from 'ai';

const vex = createVex({ /* config */ });

export async function verifiedStreamText(params: any) {
  const stream = await streamText(params);
  const verifiedStream = new TransformStream({
    transform: async (chunk, controller) => {
      const verified = await vex.verifyStreamChunk({
        chunk: chunk,
        context: params.prompt,
        spec: { type: 'streaming_workflow', threshold: 0.9 },
      });

      if (verified.valid) {
        controller.enqueue(verified.chunk);
      } else {
        controller.enqueue('[VERIFICATION_BLOCKED]');
      }
    },
  });

  return stream.pipeThrough(verifiedStream);
}

import { createVex } from '@vex_dev/sdk';
import type { ToolCall } from 'ai';

const vex = createVex({ /* config */ });

export async function verifyToolCall(toolCall: ToolCall, userContext: any) {
  const verification = await vex.verify({
    input: toolCall.args,
    spec: {
      name: 'tool_permission',
      assertions: [
        {
          type: 'permission_validation',
          required: ['api:write'],
          userContext,
        },
        {
          type: 'idempotency_check',
          key: toolCall.args.idempotencyKey,
        },
      ],
    },
  });

  if (!verification.valid) {
    throw new Error(`Tool access denied: ${verification.reason}`);
  }

  return toolCall;
}

